#!/usr/bin/env bash
# cmake/protoc-rpi4.sh — wrap the sysroot's protoc so it runs under
# qemu-user-static. CMake calls this in place of the host protoc when
# cross-building with toolchain-rpi4.cmake.
#
# The sysroot's libprotobuf-32 expects .pb.{h,cc} generated by protoc
# 3.21+ (newer header layout — `generated_message_table_driven.h` is
# gone, message_lite.h moved around). The host has only protoc 3.12,
# so we use the aarch64 protoc in the sysroot via qemu emulation.
#
# Slower than native, but the .proto set is small (~15 files) and
# only runs at clean-rebuild time.
set -e

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
SYSROOT="${RPI4_SYSROOT:-$(cd "$SCRIPT_DIR/.." && pwd)/third_party/sysroot/rpi4}"

exec qemu-aarch64-static -L "$SYSROOT" "$SYSROOT/usr/bin/protoc" "$@"
